type PatchAddItem struct {
	PhaseKey    string
	ItemKey     string
	CreateInput subscription.SubscriptionItemSpec
}

var _ subscription.ValuePatch[subscription.SubscriptionItemSpec] = PatchAddItem{}

func (a PatchAddItem) ApplyTo(spec *subscription.SubscriptionSpec, actx subscription.ApplyContext) error {
	phase, ok := spec.Phases[a.PhaseKey]
	if !ok {
		return &subscription.PatchValidationError{Msg: fmt.Sprintf("phase %s not found", a.PhaseKey)}
	}
	// ... timing guards against actx.CurrentTime ...
	phase.ItemsByKey[a.ItemKey] = append(phase.ItemsByKey[a.ItemKey], &a.CreateInput)
	return nil
}

func (r *subscriptionRepo) GetByID(ctx context.Context, subscriptionID models.NamespacedID) (subscription.Subscription, error) {
	return entutils.TransactingRepo(ctx, r, func(ctx context.Context, repo *subscriptionRepo) (subscription.Subscription, error) {
		res, err := repo.db.Subscription.Query().WithPlan().
			Where(dbsubscription.ID(subscriptionID.ID), dbsubscription.Namespace(subscriptionID.Namespace)).
			Where(SubscriptionNotDeletedAt(clock.Now())...).First(ctx)
		if db.IsNotFound(err) {
			return subscription.Subscription{}, subscription.NewSubscriptionNotFoundError(subscriptionID.ID)
		} else if err != nil {
			return subscription.Subscription{}, err
		}
		return MapDBSubscription(res)
	})
}

func (s *service) Update(ctx context.Context, subscriptionID models.NamespacedID, newSpec subscription.SubscriptionSpec) (subscription.Subscription, error) {
	ctx = subscription.NewSubscriptionOperationContext(ctx)
	view, err := s.GetView(ctx, subscriptionID)
	if err != nil { return subscription.Subscription{}, err }
	if err := s.validateUpdate(ctx, view, newSpec); err != nil { return subscription.Subscription{}, err }
	return transaction.Run(ctx, s.TransactionManager, func(ctx context.Context) (subscription.Subscription, error) {
		s.mu.RLock(); defer s.mu.RUnlock()
		_ = errors.Join(lo.Map(s.Hooks, func(v subscription.SubscriptionCommandHook, _ int) error { return v.BeforeUpdate(ctx, subscriptionID, newSpec) })...)
		subs, err := s.sync(ctx, view, newSpec)
		if err != nil { return subs, err }
		updatedView, _ := s.GetView(ctx, subs.NamespacedID)
		return subs, s.Publisher.Publish(ctx, subscription.NewUpdatedEvent(ctx, updatedView))
	})
}
